package settings

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/settings"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type InstallationSettingsProxy struct {
	settings.UnimplementedInstallationSettingsServer
	client settings.InstallationSettingsClient
}

func init() {
	proxyutil.Register(&settings.InstallationSettings_ServiceDesc, NewInstallationSettingsProxy)
}
func NewInstallationSettingsProxy(cc grpc.ClientConnInterface) settings.InstallationSettingsServer {
	return &InstallationSettingsProxy{client: settings.NewInstallationSettingsClient(cc)}
}
func (p *InstallationSettingsProxy) GetSettingsFields(ctx context.Context, in *settings.GetFieldsRequest) (*settings.GetFieldsResponse, error) {
	return proxyutil.ProxyMethod[settings.GetFieldsRequest, settings.GetFieldsResponse](p.client.GetSettingsFields)(ctx, in)
}
func (p *InstallationSettingsProxy) ValidateForm(ctx context.Context, in *settings.ValidateFormRequest) (*settings.ValidateFormResponse, error) {
	return proxyutil.ProxyMethod[settings.ValidateFormRequest, settings.ValidateFormResponse](p.client.ValidateForm)(ctx, in)
}
